 30→export async function executeRevert(
 31→  actions: RevertAction[],
 32→  dryRun: boolean,
 33→  verbose: boolean
 34→): Promise<{ succeeded: number; skipped: number }> {
 35→  let succeeded = 0;
 36→  let skipped = 0;
 37→
 38→  for (const action of actions) {
 39→    const label = `${action.skill} -> ${action.agent}`;
 40→
 41→    let stat: Awaited<ReturnType<typeof lstat>>;
 42→    try {
 43→      stat = await lstat(action.target);
